class Solution:
    def smallestGoodBase(self, n):
        num = int(n)
        # brute: the only good bases are repunits; check every digit count,
        # finding the base by a direct integer search rather than nth-root.
        best = num - 1
        m = 2
        while (1 << (m - 1)) <= num:
            # for m digits, base k satisfies sum_{i=0}^{m-1} k^i == num.
            lo, hi = 2, num - 1
            while lo <= hi:
                mid = (lo + hi) // 2
                total = 0
                p = 1
                overflow = False
                for _ in range(m):
                    total += p
                    if total > num:
                        overflow = True
                        break
                    p *= mid
                if overflow or total > num:
                    hi = mid - 1
                elif total < num:
                    lo = mid + 1
                else:
                    best = min(best, mid)
                    break
            m += 1
        return str(best)

