class Solution:
    def smallestGoodBase(self, n):
        num = int(n)
        for m in range(num.bit_length(), 1, -1):
            k = int(num ** (1.0 / (m - 1)))
            for base in (k - 1, k, k + 1):
                if base < 2:
                    continue
                total = 0
                p = 1
                for _ in range(m):
                    total += p
                    p *= base
                if total == num:
                    return str(base)
        return str(num - 1)

