var smallestGoodBase = function(n) {
    const num = BigInt(n);
    let bits = 0n;
    let t = num;
    while (t > 0n) { bits++; t >>= 1n; }
    for (let m = bits; m > 1n; m--) {
        const approx = Math.floor(Math.pow(Number(num), 1.0 / Number(m - 1n)));
        for (let d = -1; d <= 1; d++) {
            const base = BigInt(approx + d);
            if (base < 2n) continue;
            let total = 0n;
            let p = 1n;
            for (let j = 0n; j < m; j++) {
                total += p;
                p *= base;
            }
            if (total === num) return base.toString();
        }
    }
    return (num - 1n).toString();
};
